add_action( 'rest_api_init', function () {
    register_rest_route( 'demo/v1', '/books', array(
        'methods'             => 'GET',
        'permission_callback' => fn() => is_user_logged_in() && current_user_can( 'read' ),
        'callback'            => function () {
            $salt  = wp_cache_get_last_changed( 'posts' );
            $group = 'books-list';
            $key   = 'titles';
            $data  = wp_cache_get_salted( $key, $group, $salt, $found );
            if ( $found ) {
                return rest_ensure_response( $data );
            }
            $q     = new WP_Query( array( 'post_type' => 'book', 'post_status' => 'publish', 'fields' => 'titles', 'nopaging' => true ) );
            $titles = wp_list_pluck( $q->posts, 'post_title' );
            wp_cache_set_salted( $key, $titles, $group, $salt );
            return rest_ensure_response( $titles );
        },
    ) );
} );
add_action( 'save_post_book', fn() => wp_cache_delete( 'titles', 'books-list' ) );
add_action( 'deleted_post', function ( $pid ) {
    if ( get_post_type( $pid ) === 'book' ) {
        wp_cache_delete( 'titles', 'books-list' );
    }
} );
